import { useEffect, useState } from 'react'
import { useSession } from 'next-auth/react'
import { useParams, useRouter } from 'next/navigation'
import Link from 'next/link'
import ChatWindow from '@/components/ChatWindow'

export default function ConversationPage() {
  const { conversationId } = useParams()
  const { data: session, status } = useSession()
  const router = useRouter()
  const [conv, setConv] = useState(null)
  const [sessions, setSessions] = useState([])
  const [loading, setLoading] = useState(true)
  const [completing, setCompleting] = useState(false)
  const [showWhatNext, setShowWhatNext] = useState(false)

  useEffect(() => {
    if (status === 'unauthenticated') { router.push('/auth/login'); return }
    if (status === 'authenticated') {
      fetch(`/api/conversations?id=${conversationId}`)
        .then(r => r.json())
        .then(data => { setConv(data.conversation); setSessions(data.sessions || []); setLoading(false) })
    }
  }, [conversationId, status, router])

  async function confirmSession(sessionId) {
    await fetch(`/api/sessions/${sessionId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'confirmed' }),
    })
    setSessions(prev => prev.map(s => s.id === sessionId ? { ...s, status: 'confirmed' } : s))
  }

  async function completeSession(sessionId) {
    setCompleting(true)
    await fetch(`/api/sessions/${sessionId}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ status: 'completed' }),
    })
    setSessions(prev => prev.map(s => s.id === sessionId ? { ...s, status: 'completed' } : s))
    setCompleting(false)
    setShowWhatNext(true)
  }

  if (loading) return <div className="min-h-screen bg-bg flex items-center justify-center text-muted text-sm">Loading...</div>
  if (!conv) return <div className="min-h-screen bg-bg flex items-center justify-center"><p>Conversation not found</p></div>

  const other = conv.user1Id === session?.user?.id ? conv.user2 : conv.user1
  const pendingSession = sessions.find(s => s.status === 'pending')
  const confirmedSession = sessions.find(s => s.status === 'confirmed')
  const isProvider = pendingSession?.providerId === session?.user?.id || confirmedSession?.providerId === session?.user?.id

  return (
    <div className="min-h-screen bg-bg flex flex-col">
      <div className="max-w-2xl mx-auto w-full flex-1 flex flex-col py-4 px-4">
        <div className="card flex-1 flex flex-col overflow-hidden">
          <ChatWindow conversationId={conversationId} otherUser={other} />
        </div>

        {/* Session actions */}
        {pendingSession && isProvider && (
          <div className="mt-3 p-4 bg-amber-50 border border-amber-200 rounded-xl flex items-center justify-between gap-3">
            <div>
              <p className="text-sm font-semibold text-amber-800">Session requested</p>
              <p className="text-xs text-amber-700 mt-0.5">For: {pendingSession.post?.title}</p>
            </div>
            <div className="flex gap-2">
              <button onClick={() => confirmSession(pendingSession.id)} className="text-sm px-4 py-2 bg-primary text-white rounded-lg hover:bg-primary-800 transition">Confirm</button>
              <button onClick={async () => {
