  const router = useRouter()
  const [data, setData] = useState(null)
  const [loading, setLoading] = useState(true)

  useEffect(() => {
    if (status === 'unauthenticated') { router.push('/auth/login'); return }
    if (status === 'authenticated') {
      Promise.all([
        fetch('/api/sessions').then(r => r.json()),
        fetch(`/api/users/${session.user.id}`).then(r => r.json()),
      ]).then(([sessData, userData]) => {
        setData({ sessions: sessData.sessions || [], posts: userData.user?.posts || [] })
        setLoading(false)
      })
    }
  }, [status, session, router])

  if (loading) return <div className="min-h-screen bg-bg flex items-center justify-center text-muted text-sm">Loading...</div>

  const upcoming = data.sessions.filter(s => ['pending', 'confirmed'].includes(s.status))
  const history = data.sessions.filter(s => ['completed', 'cancelled'].includes(s.status))
  const activePosts = data.posts.filter(p => p.isActive)

  return (
    <div className="min-h-screen bg-bg py-10 px-4">
      <div className="max-w-3xl mx-auto">
        <div className="flex items-center justify-between mb-8">
          <div>
            <h1 className="text-2xl font-bold text-neutral-charcoal">Dashboard</h1>
            <p className="text-muted text-sm mt-0.5">Welcome back, {session?.user?.name?.split(' ')[0]}</p>
          </div>
          <Link href="/post/new" className="btn-accent text-sm px-5 py-2.5">+ Post a skill</Link>
        </div>

        {/* Upcoming sessions */}
        <section className="mb-10">
          <h2 className="text-lg font-bold text-neutral-charcoal mb-4">Upcoming sessions</h2>
          {upcoming.length === 0 ? (
            <div className="card p-8 text-center">
              <p className="text-muted text-sm">No upcoming sessions.</p>
              <Link href="/browse" className="text-primary text-sm font-medium hover:underline mt-2 block">Browse skills to get started</Link>
            </div>
          ) : (
            <div className="space-y-3">
              {upcoming.map(s => <SessionCard key={s.id} session={s} currentUserId={session.user.id} />)}
            </div>
          )}
        </section>

        {/* My listings */}
        <section className="mb-10">
          <h2 className="text-lg font-bold text-neutral-charcoal mb-4">My listings</h2>
          {activePosts.length === 0 ? (
            <div className="card p-8 text-center">
              <p className="text-muted text-sm">You have no active listings.</p>
              <Link href="/post/new" className="text-primary text-sm font-medium hover:underline mt-2 block">Post your first skill</Link>
            </div>
          ) : (
            <div className="grid sm:grid-cols-2 gap-4">
              {activePosts.map(p => <PostCard key={p.id} post={{...p, user: {name: session.user.name, id: session.user.id}}} />)}
            </div>
          )}
        </section>

        {/* Session history */}
        {history.length > 0 && (
          <section>
            <h2 className="text-lg font-bold text-neutral-charcoal mb-4">Session history</h2>
            <div className="space-y-3">
              {history.map(s => <SessionCard key={s.id} session={s} currentUserId={session.user.id} />)}
            </div>
          </section>
        )}
      </div>
    </div>
  )
}

